1	export type Cell = [number, number];
2	
3	const NEIGHBOR_OFFSETS: Cell[] = [
4	  [-1, -1], [-1, 0], [-1, 1],
5	  [ 0, -1],          [ 0, 1],
6	  [ 1, -1], [ 1, 0], [ 1, 1],
7	];
8	
9	const cellKey = ([x, y]: Cell): string => `${x},${y}`;
10	
11	const neighborsOf = ([x, y]: Cell): Cell[] =>
12	  NEIGHBOR_OFFSETS.map(([dx, dy]) => [x + dx, y + dy]);
13	
14	const countNeighbors = (liveCells: Cell[]): Map<string, { cell: Cell; count: number }> => {
15	  const counts = new Map<string, { cell: Cell; count: number }>();
16	  for (const liveCell of liveCells) {
17	    for (const neighbor of neighborsOf(liveCell)) {
18	      const k = cellKey(neighbor);
19	      const existing = counts.get(k);
20	      counts.set(k, { cell: neighbor, count: (existing?.count ?? 0) + 1 });
21	    }
22	  }
23	  return counts;
24	};
25	
26	export const nextGeneration = (liveCells: Cell[]): Cell[] => {
27	  const liveKeys = new Set(liveCells.map(cellKey));
28	  const neighborCounts = countNeighbors(liveCells);
29	
30	  const survives = (k: string, count: number): boolean =>
31	    count === 3 || (count === 2 && liveKeys.has(k));
32	
33	  return [...neighborCounts]
34	    .filter(([k, { count }]) => survives(k, count))
35	    .map(([, { cell }]) => cell);
36	};
