const countNeighbors = (liveCells: Cell[]): Map<string, { cell: Cell; count: number }> => {
  const counts = new Map<string, { cell: Cell; count: number }>();
  for (const liveCell of liveCells) {
    for (const neighbor of neighborsOf(liveCell)) {
      const k = cellKey(neighbor);
      const existing = counts.get(k);
      counts.set(k, { cell: neighbor, count: (existing?.count ?? 0) + 1 });
    }
  }
  return counts;
};

export const nextGeneration = (liveCells: Cell[]): Cell[] => {
  const liveKeys = new Set(liveCells.map(cellKey));
  const neighborCounts = countNeighbors(liveCells);

  const survives = (k: string, count: number): boolean =>
    count === 3 || (count === 2 && liveKeys.has(k));

  return [...neighborCounts]
    .filter(([k, { count }]) => survives(k, count))
    .map(([, { cell }]) => cell);
};

